def count_subarrays_sum_to_k(nums, k):
    seen = {0: 1}
    total = 0
    ans = 0
    for x in nums:
        total += x
        ans += seen.get(total - k, 0)
        seen[total] = seen.get(total, 0) + 1
    return ans

